- Sunny weather condition typically refers to clear skies with more than 60% sunshine throughout the day; 
- The year 2023 refers to the calendar year from January 1, 2023, to December 31, 2023; 
- Leisure trips are those taken for recreation, relaxation, or entertainment purposes rather than for business or work-related activities; 
- Total expenses exceeding $100 imply activities with aggregate costs higher than this threshold.

sql:
SELECT MAX(amount) AS max_lodging_expense
FROM trip_expenses
WHERE expense_type = 'lodging';

SELECT amount
FROM trip_expenses
WHERE amount > 50.0;

SELECT traveler_name, traveler_type
FROM travelers
ORDER BY traveler_name;

SELECT COUNT(*) 
FROM travelers 
WHERE traveler_type = 'frequent';

SELECT COUNT(*) AS total_activities
FROM trip_activities
WHERE activity_location = 'Paris, France';
